INSERT INTO public.questions (id, banca, year, discipline, subject, text, alternatives, correct, explanation) VALUES ('Q-28491', 'CRS/PMMG', 2023, 'Direito Constitucional', 'Forças Armadas e Segurança Pública', 'No que tange aos direitos, deveres e regramento constitucional dos militares dos Estados, Distrito Federal e Territórios, bem como à organização das Forças Armadas, assinale a alternativa CORRETA em conformidade com a Constituição Federal de 1988:', '[{"letter":"A","text":"As Forças Armadas são constituídas pela Marinha, pelo Exército, pela Aeronáutica e pelas Forças Auxiliares, sendo estas últimas organizadas sob comando da união em tempo de paz."},{"letter":"B","text":"Ao militar são proibidas a sindicalização e a greve, sendo-lhe, contudo, permitido o alistamento eleitoral e a filiação a partidos políticos enquanto estiver em serviço ativo."},{"letter":"C","text":"O militar em serviço ativo que aceitar cargo público civil permanente será transferido para a reserva, nos termos da lei, mantendo o direito à promoção por antiguidade."},{"letter":"D","text":"O oficial da Polícia Militar só perderá o posto e a patente se for julgado indigno do oficialato ou com ele incompatível, por decisão de tribunal militar de caráter permanente ou de tribunal de justiça comum."}]'::jsonb, 'D', 'O Art. 142, § 3º, VI da CF/88, aplicável aos militares dos Estados por força do Art. 42, § 1º, estabelece que o oficial só perderá o posto e a patente se for julgado indigno do oficialato ou com ele incompatível, por decisão de tribunal militar de caráter permanente em tempo de paz ou de tribunal especial em tempo de guerra. O Art. 42, § 2º dita que o tribunal militar estadual ou o Tribunal de Justiça apreciará a indignidade.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, banca, year, discipline, subject, text, alternatives, correct, explanation) VALUES ('Q-19042', 'CRS/PMMG', 2024, 'Regulamento Disciplinar', 'CEDM - Lei Estadual 14.310/02', 'O Código de Ética e Disciplina dos Militares de Minas Gerais (Lei Estadual nº 14.310/2002) regulamenta a conduta militar. Diante das disposições contidas na referida lei, assinale a opção que indica uma transgressão disciplinar classificada como GRAVE:', '[{"letter":"A","text":"Deixar de apresentar-se, logo que ciente, à autoridade competente quando convocado para depor ou prestar esclarecimentos em inquérito administrativo."},{"letter":"B","text":"Faltar ao serviço para o qual esteja nominalmente escalado ou abandonar o posto ou serviço para o qual tenha sido designado, sem justa causa."},{"letter":"C","text":"Apresentar-se para o serviço sem o fardamento regulamentar previsto para a atividade, ou com fardamento desalinhado ou incompleto."},{"letter":"D","text":"Deixar de prestar a devida continência militar a superior hierárquico ou de responder à continência de subordinado, por mera desatenção."}]'::jsonb, 'B', 'Faltar ou abandonar o posto/serviço sem justa causa é uma transgressão de natureza GRAVE (Art. 13 do CEDM). As demais alternativas tratam de transgressões médias ou leves, ou configuram condutas de menor potencial ofensivo disciplinar.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, banca, year, discipline, subject, text, alternatives, correct, explanation) VALUES ('Q-32405', 'CRS/PMMG', 2023, 'Direito Administrativo', 'Atos Administrativos', 'O ato administrativo consiste na declaração do Estado ou de quem o represente, que produz efeitos jurídicos imediatos. Dentre os elementos ou requisitos de validade do ato administrativo, assinale a alternativa que descreve CORRETAMENTE o elemento da ''Competência'':', '[{"letter":"A","text":"É o efeito jurídico imediato que o ato produz na ordem jurídica, devendo sempre ser lícito e moral."},{"letter":"B","text":"Consiste no poder outorgado por lei ao agente público para o desempenho de suas atribuições, sendo este um requisito intransferível e inderrogável por acordo das partes."},{"letter":"C","text":"Representa a motivação de fato e de direito que autorizou a expedição e o conteúdo do ato público administrativo."},{"letter":"D","text":"Trata-se do procedimento externo exigido por lei para a perfeita exteriorização da vontade do administrador."}]'::jsonb, 'B', 'A competência (ou sujeito) é o poder outorgado pela lei ao agente público para o exercício de suas funções. Apresenta como características a irrenunciabilidade, a intransferibilidade e a inderrogabilidade (salvo os casos legais de delegação e avocação).') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, banca, year, discipline, subject, text, alternatives, correct, explanation) VALUES ('Q-45019', 'CRS/PMMG', 2022, 'Direito Penal Militar', 'Crimes Contra a Autoridade ou Disciplina', 'De acordo com o Código Penal Militar (Decreto-Lei nº 1.001/1969), o crime de Recusa de Obediência (Art. 163) configura crime de extrema gravidade para o serviço de caserna. Assinale a conduta típica que caracteriza esse crime:', '[{"letter":"A","text":"Deixar de cumprir ordem recebida de superior hierárquico sobre assunto de serviço ou dever imposto em lei, regulamento ou instrução."},{"letter":"B","text":"Recusar obediência a ordem do superior sobre assunto de serviço, ou de dever imposto por lei, regulamento ou instrução."},{"letter":"C","text":"Promover a reunião de militares ou nela tomar parte, para discutir ato de superior ou assunto disciplinar interno."},{"letter":"D","text":"Opor-se à execução de ato legal, mediante violência ou ameaça a superior ou sentinela."}]'::jsonb, 'B', 'O crime de Recusa de Obediência (Art. 163 do CPM) tem como núcleo ''recusar obediência a ordem do superior sobre assunto de serviço, ou de dever imposto sob preceito de lei, regulamento ou instrução''. Deixar de cumprir ordem (sem recusa expressa) tipifica o crime de Deserção de Dever ou Prevaricação/Descumprimento de Serviço do Art. 196 ou outro tipo penal específico.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, banca, year, discipline, subject, text, alternatives, correct, explanation) VALUES ('Q-11482', 'CRS/PMMG', 2024, 'Direito Constitucional', 'Remédios Constitucionais', 'Os remédios constitucionais são garantias fundamentais destinadas a assegurar o exercício de direitos individuais violados por atos de autoridade. No contexto das atividades policiais e do controle de legalidade, assinale a afirmativa CORRETA referente ao Mandado de Segurança Coletivo:', '[{"letter":"A","text":"Pode ser impetrado por qualquer cidadão em pleno gozo de seus direitos políticos, visando anular ato lesivo ao patrimônio público."},{"letter":"B","text":"Pode ser impetrado por partido político com representação no Congresso Nacional, ou por organização sindical, entidade de classe ou associação legalmente constituída e em funcionamento há pelo menos um ano, em defesa dos interesses de seus membros ou associados."},{"letter":"C","text":"Consiste na ação judicial cabível sempre que a falta de norma regulamentadora torne inviável o exercício dos direitos e liberdades constitucionais."},{"letter":"D","text":"É o remédio cabível para assegurar o conhecimento de informações relativas à pessoa do impetrante, constantes de registros ou bancos de dados governamentais."}]'::jsonb, 'B', 'O Art. 5º, LXX da CF/88 estabelece que o mandado de segurança coletivo pode ser impetrado por: a) partido político com representação no Congresso Nacional; b) organização sindical, entidade de classe ou associação legalmente constituída e em funcionamento há pelo menos um ano, em defesa dos interesses de seus membros ou associados.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.law_articles (id, title, category, citation, content, related_questions) VALUES ('lei-01', 'Artigo 142 da Constituição Federal (Das Forças Armadas)', 'Constituição da República Federativa do Brasil de 1988', 'Art. 142, CF/88', 'As Forças Armadas, constituídas pela Marinha, pelo Exército e pela Aeronáutica, são instituições nacionais permanentes e regulares, organizadas com base na hierarquia e na disciplina, sob a autoridade suprema do Presidente da República, e destinam-se à defesa da Pátria, à garantia dos poderes constitucionais e, por iniciativa de qualquer destes, da lei e da ordem.
INSERT INTO public.law_articles (id, title, category, citation, content, related_questions) VALUES ('lei-02', 'Artigo 144 da Constituição Federal (Da Segurança Pública)', 'Constituição da República Federativa do Brasil de 1988', 'Art. 144, CF/88', 'A segurança pública, dever do Estado, direito e responsabilidade de todos, é exercida para a preservação da ordem pública e da incolumidade das pessoas e do patrimônio, através dos seguintes órgãos:
INSERT INTO public.law_articles (id, title, category, citation, content, related_questions) VALUES ('lei-03', 'Artigo 13 do CEDM (Classificação das Transgressões)', 'Regulamento Disciplinar', 'Art. 13, Lei Estadual 14.310/02', 'As transgressões disciplinares são classificadas em graves, médias e leves, conforme sua gravidade e repercussão no serviço ou na imagem das Instituições Militares Estaduais.
INSERT INTO public.law_articles (id, title, category, citation, content, related_questions) VALUES ('lei-04', 'Artigo 163 do Código Penal Militar (Recusa de Obediência)', 'Penal Militar', 'Art. 163, Dec-Lei 1.001/69', 'Recusar obediência a ordem do superior sobre assunto de serviço, ou de dever imposto sob preceito de lei, regulamento ou instrução:
INSERT INTO public.law_articles (id, title, category, citation, content, related_questions) VALUES ('lei-05', 'Artigo 5º da Constituição Federal (Direitos e Deveres Individuais e Coletivos)', 'Constituição da República Federativa do Brasil de 1988', 'Art. 5º, CF/88', 'Todos são iguais perante a lei, sem distinção de qualquer natureza, garantindo-se aos brasileiros e aos estrangeiros residentes no País a inviolabilidade do direito à vida, à liberdade, à igualdade, à segurança e à propriedade, nos termos seguintes:
